const input = $json;
const records = [];
if (input.master_resume) {
  const chunks = String(input.master_resume).match(/[\s\S]{1,1800}/g) || [];
  chunks.forEach((text, index) => records.push({ id: `resume_${index + 1}`, text, metadata: { type: 'resume_chunk', section: 'master_resume', chunk_index: index } }));
}
if (input.description) {
  records.push({ id: `${input.job_id || 'job'}_description`, text: input.description, metadata: { type: 'job_description', job_id: input.job_id || '', company_name: input.company_name || '', role_title: input.title || '', source_url: input.job_url || '' } });
}
if (input.company_research) {
  const text = typeof input.company_research === 'string' ? input.company_research : JSON.stringify(input.company_research);
  records.push({ id: `${input.job_id || input.company_name || 'company'}_research`, text, metadata: { type: 'company_research', job_id: input.job_id || '', company_name: input.company_name || '', source_url: input.company_website || input.company_url || '' } });
}
return records.map((record) => ({ json: record }));

const source = $('Build Vector Records').item.json;
const vector = $json.data?.[0]?.embedding || [];
return [{ json: {
  vectors: [{
    id: source.id,
    values: vector,
    metadata: { ...source.metadata, text: source.text.slice(0, 4000), created_at: new Date().toISOString() }
  }],
  namespace: $env.PINECONE_NAMESPACE || 'job-application-agent'
}}];
